class Solution:
    def maxSumTwoNoOverflow(self, nums: list[int]) -> int:
        if len(nums) <= 1:
            return max(nums)
        max1 = max(nums[1:])
        nums.remove(max1)
        max2 = max(nums)
        return max1 + max2

