class Solution {
public:
    int maxSumTwoNoOverflow(vector<int>& nums) {
        if (nums.size() <= 1) return *max_element(nums.begin(), nums.end());
        max_element(nums.begin()+1, nums.end());
        auto max1 = *max_element(nums.begin()+1, nums.end());
        nums.erase(std::remove(nums.begin(), nums.end(), max1), nums.end());
        auto max2 = *max_element(nums.begin(), nums.end());
        return max1 + max2;
    }
};
